export default ChatWindow;

import React, { useState } from 'react';
import { Send, Mic, Paperclip } from 'lucide-react';

interface ChatInputProps {
  onSend: (message: string) => void;
  disabled?: boolean;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState('');

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (input.trim() && !disabled) {
      onSend(input.trim());
      setInput('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-white via-white/90 to-transparent pointer-events-none">
      <div className="max-w-4xl mx-auto flex items-center gap-2 bg-white border border-gray-200 shadow-xl shadow-gray-200/50 rounded-2xl p-2 pointer-events-auto">
        <button 
          className="p-3 text-gray-400 hover:text-emerald-600 transition-colors"
          title="Upload File (UI only)"
        >
          <Paperclip size={20} />
        </button>

        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Type your message..."
          rows={1}
          className="flex-1 bg-transparent border-none focus:ring-0 text-[15px] resize-none py-3 placeholder-gray-400 overflow-hidden"
          disabled={disabled}
        />

        <div className="flex items-center gap-1">
          <button 
            className="p-3 text-gray-400 hover:text-emerald-600 transition-colors"
            title="Voice Input (UI only)"
          >
            <Mic size={20} />
          </button>

          <button
            onClick={() => handleSubmit()}
            disabled={!input.trim() || disabled}
            className={`p-3 rounded-xl transition-all duration-200 ${
              input.trim() && !disabled
                ? 'bg-emerald-600 text-white shadow-md shadow-emerald-200 hover:bg-emerald-700'
                : 'bg-gray-50 text-gray-300 cursor-not-allowed'
            }`}
          >
            <Send size={20} />
          </button>
        </div>
      </div>
      <div className="text-center mt-3 text-[10px] text-gray-400 font-medium">
        Emerald AI v1.0.0 (Academic Edition) | MCA Research Submission
      </div>
    </div>
  );
};

export default ChatInput;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ChatInput from './components/ChatInput';
import { ChatSession, Message, UserProfile } from './types';
import { generateAIResponse } from './services/geminiService';

const MOCK_USER: UserProfile = {
  name: "Aditya Sharma",
  email: "aditya.sharma.mca@university.edu",
  role: "Postgraduate Student"
};

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Initialize with a new session if empty
  useEffect(() => {
    if (sessions.length === 0) {
      handleNewChat();
    }
  }, []);

  const handleNewChat = useCallback(() => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: "New Conversation",
      messages: [],
      createdAt: new Date(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
  }, []);

  const handleSelectSession = useCallback((id: string) => {
    setActiveSessionId(id);
  }, []);

  const handleSendMessage = async (content: string) => {
    if (!activeSessionId) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date()
    };

    // Optimistically update UI
    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        // If it's the first message, update title
        const newTitle = s.messages.length === 0 ? content.slice(0, 30) + (content.length > 30 ? '...' : '') : s.title;
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    // Prepare history for Gemini API
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const apiHistory = activeSession?.messages.map(m => ({
      role: m.role,
      parts: [{ text: m.content }]
    })) || [];

    const aiResponseText = await generateAIResponse(content, apiHistory);

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-white overflow-hidden">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        user={MOCK_USER}
      />

      <main className="flex-1 flex flex-col relative h-full">
        {/* Simple Top Banner for Context */}
        <header className="h-16 border-b border-gray-100 flex items-center justify-between px-8 bg-white/80 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <span className="text-emerald-600 font-bold text-lg tracking-tight">Emerald.ai</span>
            <div className="h-4 w-[1px] bg-gray-200"></div>
            <span className="text-sm font-medium text-gray-500 truncate max-w-[200px]">
              {activeSession?.title || 'Home'}
            </span>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded uppercase tracking-widest">
               Reasoning Enabled
             </span>
          </div>
        </header>

        <ChatWindow 
          messages={activeSession?.messages || []} 
          isLoading={isLoading} 
        />

        <ChatInput onSend={handleSendMessage} disabled={isLoading} />
      </main>
    </div>
  );
};

export default App;

{
  "name": "Emerald Intelligence - Professional Botanical AI",
  "description": "A production-grade, academic-standard AI chatbot specialized in plant identification, classification, and botanical research using Gemini Vision.",
  "requestFramePermissions": ["camera"]
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export interface MediaPart {
  inlineData: {
    mimeType: string;
    data: string;
  };
}

export const generateAIResponse = async (
  prompt: string, 
  history: { role: string; parts: ( { text: string } | MediaPart )[] }[],
  image?: { mimeType: string; data: string }
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const contents: any[] = [...history];
    const currentParts: any[] = [{ text: prompt }];

    if (image) {
      currentParts.push({
        inlineData: {
          mimeType: image.mimeType,
          data: image.data,
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: `You are a Senior Botanical Scientist and Plant Pathologist. 
        Your goal is to provide expert-level plant identification, classification (Kingdom, Division, Class, Order, Family, Genus, Species), and health analysis.
        When an image is provided:
        1. Identify the plant precisely.
        2. Provide scientific and common names.
        3. Analyze health status (check for pests, nutrient deficiencies).
        4. Suggest care instructions.
        Always maintain a professional, academic, and clinical tone. Use markdown tables for classification data.`,
        temperature: 0.4,
        topP: 0.8,
        topK: 40
      }
    });

    return response.text || "I'm sorry, I couldn't identify this specimen.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Botanical Engine Error: Unable to analyze the specimen. Please ensure the image is clear and try again.";
  }
};

