export default MessageBubble;

import React, { useState, useRef } from 'react';
import { Send, Camera, Image as ImageIcon, X, Loader2 } from 'lucide-react';

interface ChatInputProps {
  onSend: (message: string, image?: { mimeType: string, data: string, url: string }) => void;
  disabled?: boolean;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<{ mimeType: string, data: string, url: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage({
          mimeType: file.type,
          data: (reader.result as string).split(',')[1],
          url: reader.result as string
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if ((input.trim() || selectedImage) && !disabled) {
      onSend(input.trim() || "Analyze this specimen.", selectedImage || undefined);
      setInput('');
      setSelectedImage(null);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-white via-white/95 to-transparent pointer-events-none">
      <div className="max-w-4xl mx-auto pointer-events-auto">

        {/* Image Preview Area */}
        {selectedImage && (
          <div className="mb-3 flex items-center p-2 bg-emerald-50/80 backdrop-blur rounded-2xl border border-emerald-100 w-fit">
            <div className="relative w-16 h-16 rounded-lg overflow-hidden border border-emerald-200 shadow-sm">
              <img src={selectedImage.url} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute top-0 right-0 p-1 bg-black/50 text-white hover:bg-black/70 transition-colors"
              >
                <X size={12} />
              </button>
            </div>
            <div className="ml-3 pr-4">
              <p className="text-xs font-bold text-emerald-800">Specimen Loaded</p>
              <p className="text-[10px] text-emerald-600 uppercase tracking-widest font-bold">Ready for classification</p>
            </div>
          </div>
        )}

        <div className="flex items-center gap-3 bg-white border border-gray-200 shadow-2xl shadow-emerald-900/10 rounded-3xl p-3">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-3 text-gray-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-2xl transition-all"
            title="Upload Specimen"
          >
            <ImageIcon size={22} />
          </button>

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Describe the plant or ask for identification..."
            rows={1}
            className="flex-1 bg-transparent border-none focus:ring-0 text-[15px] resize-none py-3 placeholder-gray-400 font-medium"
            disabled={disabled}
          />

          <button
            onClick={() => handleSubmit()}
            disabled={( !input.trim() && !selectedImage ) || disabled}
            className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all duration-300 ${
              (input.trim() || selectedImage) && !disabled
                ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200 hover:bg-emerald-700 hover:-translate-y-0.5'
                : 'bg-gray-100 text-gray-300 cursor-not-allowed'
            }`}
          >
            {disabled ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
            <span>{disabled ? 'Analyzing...' : 'Analyze'}</span>
          </button>
        </div>

        <div className="flex justify-center gap-4 mt-4">
           {['Identify', 'Care Guide', 'Health Check'].map(tag => (
             <button 
               key={tag}
               onClick={() => setInput(tag)}
               className="text-[10px] font-bold text-emerald-600/60 hover:text-emerald-600 uppercase tracking-[0.2em] transition-colors"
             >
               {tag}
             </button>
           ))}
        </div>
      </div>
    </div>
  );
};

export default ChatInput;

