import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export interface MediaPart {
  inlineData: {
    mimeType: string;
    data: string;
  };
}

export const generateAIResponse = async (
  prompt: string, 
  history: { role: string; parts: ( { text: string } | MediaPart )[] }[],
  image?: { mimeType: string; data: string }
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const contents: any[] = [...history];
    const currentParts: any[] = [{ text: prompt }];

    if (image) {
      currentParts.push({
        inlineData: {
          mimeType: image.mimeType,
          data: image.data,
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: `You are the "Emerald Botanical Expert," an elite plant pathologist and landscape architect. 
        Your capabilities include:

        1. DISEASE DIAGNOSIS: If a photo of a sick plant is provided, diagnose the issue (fungal, pest, nutrient) and provide a treatment plan.
        2. SPACE ANALYSIS: If a photo of an empty space (balcony, room, garden patch) is provided, identify light conditions and suggest 3 specific plants that would thrive there.
        3. GENERAL BOTANY: Provide advantages, disadvantages, growth requirements (pH, water, light), and scientific classification for any plant mentioned.
        4. CROP CYCLES: Advise on seasonal planting (e.g., what to plant in spring vs winter).

        OUTPUT STYLE:
        - Use structured Markdown.
        - Use bold headings.
        - Use tables for "Pros & Cons" or "Care Requirements."
        - Keep the tone professional, clinical, and helpful.`,
        temperature: 0.3,
        topP: 0.8,
      }
    });

    return response.text || "I apologize, the botanical engine could not process this specimen.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Diagnostic Error: I encountered an issue analyzing the specimen. Please ensure the lighting is adequate and the subject is in focus.";
  }
};

import React, { useRef, useState, useEffect } from 'react';
import { X, Camera as CameraIcon, RefreshCw } from 'lucide-react';

interface CameraModalProps {
  onCapture: (dataUrl: string) => void;
  onClose: () => void;
}

const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment' }, 
          audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) {
        console.error("Camera access error:", err);
        alert("Could not access camera. Please check permissions.");
        onClose();
      }
    }
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, []);

  const capture = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        onCapture(dataUrl);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4">
      <div className="relative w-full max-w-2xl aspect-[4/3] bg-neutral-900 rounded-3xl overflow-hidden shadow-2xl">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
        <canvas ref={canvasRef} className="hidden" />

        <div className="absolute inset-x-0 bottom-8 flex justify-center items-center gap-8">
          <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors">
            <X size={24} />
          </button>
          <button onClick={capture} className="p-6 bg-emerald-500 hover:bg-emerald-400 rounded-full text-white shadow-xl shadow-emerald-500/30 transition-all active:scale-95">
            <CameraIcon size={32} />
          </button>
          <div className="w-14" /> {/* Spacer */}
        </div>
      </div>
    </div>
  );
};

