import React, { useState, useRef } from 'react';
import { Send, Camera, Image as ImageIcon, X, Loader2, Sparkles } from 'lucide-react';
import CameraModal from './CameraModal';

interface ChatInputProps {
  onSend: (message: string, image?: { mimeType: string, data: string, url: string }) => void;
  disabled?: boolean;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<{ mimeType: string, data: string, url: string } | null>(null);
  const [showCamera, setShowCamera] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage({
          mimeType: file.type,
          data: (reader.result as string).split(',')[1],
          url: reader.result as string
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCameraCapture = (dataUrl: string) => {
    setSelectedImage({
      mimeType: 'image/jpeg',
      data: dataUrl.split(',')[1],
      url: dataUrl
    });
  };

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if ((input.trim() || selectedImage) && !disabled) {
      onSend(input.trim() || "Analyze this botanical specimen.", selectedImage || undefined);
      setInput('');
      setSelectedImage(null);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-white via-white/95 to-transparent pointer-events-none">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      <div className="max-w-4xl mx-auto pointer-events-auto">
        {selectedImage && (
          <div className="mb-4 flex items-center p-3 bg-emerald-50/90 backdrop-blur-md rounded-2xl border border-emerald-100 w-fit shadow-lg shadow-emerald-900/5 animate-in slide-in-from-bottom-2">
            <div className="relative w-20 h-20 rounded-xl overflow-hidden border-2 border-white shadow-md">
              <img src={selectedImage.url} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute top-1 right-1 p-1 bg-black/60 text-white rounded-full hover:bg-black/80 transition-colors"
              >
                <X size={12} />
              </button>
            </div>
            <div className="ml-4 pr-6">
              <p className="text-sm font-bold text-emerald-900 flex items-center gap-2">
                <Sparkles size={14} className="text-emerald-500" />
                Specimen Ready
              </p>
              <p className="text-[10px] text-emerald-600/70 uppercase tracking-widest font-black mt-0.5">Analysis pending submission</p>
            </div>
          </div>
        )}

        <div className="flex items-center gap-2 bg-white border border-emerald-100 shadow-2xl shadow-emerald-900/10 rounded-[2.5rem] p-2 pr-4 pl-4 focus-within:border-emerald-300 transition-all duration-300 group">
          <button 
            onClick={() => setShowCamera(true)}
            className="p-3 text-emerald-600 hover:bg-emerald-50 rounded-full transition-all active:scale-90"
            title="Open Camera"
          >
            <Camera size={22} />
          </button>

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-3 text-emerald-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full transition-all"
            title="Upload Photo"
          >
            <ImageIcon size={22} />
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          </button>

          <div className="w-[1px] h-8 bg-emerald-50 mx-1" />

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask about a disease, requirement, or advantage..."
            rows={1}
            className="flex-1 bg-transparent border-none focus:ring-0 text-[15px] resize-none py-3 placeholder-emerald-900/20 font-medium text-emerald-950"
            disabled={disabled}
          />

          <button
            onClick={() => handleSubmit()}
            disabled={( !input.trim() && !selectedImage ) || disabled}
            className={`flex items-center justify-center w-12 h-12 rounded-full transition-all duration-500 ${
              (input.trim() || selectedImage) && !disabled
                ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200 hover:bg-emerald-700 hover:scale-105 active:scale-95'
                : 'bg-emerald-50 text-emerald-200 cursor-not-allowed'
            }`}
          >
            {disabled ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} />}
          </button>
        </div>

        <div className="flex justify-center gap-6 mt-4">
           {[
             { label: 'Diagnose Disease', icon: '🧬' },
             { label: 'Space Recommendation', icon: '🏠' },
             { label: 'Advantages', icon: '✅' }
           ].map(tag => (
             <button 
               key={tag.label}
               onClick={() => setInput(prev => prev + ' ' + tag.label)}
