           <img 
             src="https://images.unsplash.com/photo-1518531933037-91b2f5f229cc?q=80&w=2000&auto=format&fit=crop" 
             className="w-full h-full object-cover opacity-30 grayscale"
             alt="Botanical Texture"
           />
           <div className="absolute inset-0 bg-gradient-to-tr from-[#021811] via-transparent to-[#021811]/20"></div>
        </div>

        <div className="relative z-10 text-white space-y-12">
           <div className="flex items-center gap-5">
              <div className="w-20 h-20 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center shadow-[0_0_50px_rgba(16,185,129,0.3)]">
                 <Leaf size={42} className="text-[#021811]" />
