                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                  placeholder="name@email.com"
                />
              </div>
