            <p style="font-size: 11px; color: #94a3b8; text-transform: uppercase; letter-spacing: 1.5px; text-align: center; font-weight: 700;">This code will expire shortly. Security protocol active.</p>
          </div>
        `
      });

      if (response === "OK") return true;
      setError({ message: `Protocol Refused: ${response}` });
      return false;
    } catch (e) {
      console.error("SMTP Exception:", e);
      setError({ message: "Mail server unreachable. Check your firewall settings." });
      return false;
    }
  };

  const handleInitialSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (isRegistering) {
      if (!(window as any).Email) {
        setError({ message: "Security system is currently offline. Ensure ad-blockers are disabled." });
        return;
      }

      setLoading(true);
      const newOtp = Math.floor(100000 + Math.random() * 900000).toString();
      setGeneratedOtp(newOtp);

      const success = await sendOtpEmail(email, newOtp);
      setLoading(false);

      if (success) {
        setStep('otp');
        setResendTimer(60);
      }
    } else {
      setLoading(true);
      try {
        await login(email, password);
      } catch (err: any) {
        let msg = "Authentication Rejected";
        if (err.code === 'auth/wrong-password') msg = "Invalid researcher key.";
        if (err.code === 'auth/user-not-found') msg = "Identity not found in database.";
        setError({ message: msg });
      } finally {
        setLoading(false);
      }
    }
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value.slice(-1);
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    if (value && index < 5) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleVerifyOtp = async () => {
    const enteredCode = otp.join('');
    if (enteredCode !== generatedOtp) {
      setError({ message: "Validation failed. Incorrect researcher key." });
      return;
    }

    setLoading(true);
    try {
      await register(email, password, name);
    } catch (err: any) {
      setError({ message: err.message || "Registration sequence failed." });
    } finally {
      setLoading(false);
    }
  };

  const handleResend = async () => {
    if (resendTimer > 0) return;
    setLoading(true);
    setError(null);
    const newOtp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(newOtp);
    const success = await sendOtpEmail(email, newOtp);
    if (success) {
      setResendTimer(60);
    }
    setLoading(false);
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fbf9] overflow-hidden">
