                    <span className="leading-normal">{error.message.toUpperCase()}</span>
                  </div>
                )}

                {!isSmtpLoaded && isRegistering && !smtpInitializationFailed && (
                  <div className="p-4 bg-emerald-50 border border-emerald-100 rounded-2xl flex items-center gap-3">
                    <Loader2 size={14} className="animate-spin text-emerald-600" />
                    <span className="text-[10px] font-black text-emerald-700 uppercase tracking-widest">Waking Security Engine...</span>
                  </div>
                )}

                {smtpInitializationFailed && isRegistering && (
                  <div className="space-y-4">
