                  {loading ? <Loader2 className="animate-spin" size={24} /> : (
                    <>
                      <span className="uppercase tracking-[0.2em]">{isRegistering ? 'Verify Identity' : 'Authorize Entrance'}</span>
                      <ArrowRight size={22} />
                    </>
                  )}
                </button>
              </form>

              <div className="text-center">
                <button
                  onClick={() => { setIsRegistering(!isRegistering); setError(null); }}
                  className="text-xs font-black text-emerald-950/40 hover:text-emerald-950 transition-colors uppercase tracking-[0.2em]"
                >
                  {isRegistering ? 'Member of the core? Log In' : 'Join botanical network? Register'}
                </button>
              </div>
            </>
          ) : (
            // OTP STEP
            <div className="space-y-10 animate-in zoom-in-95 duration-300">
              <div className="text-center space-y-4">
                <div className="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center mx-auto mb-6">
                  <ShieldCheck size={32} className="text-emerald-600" />
                </div>
                <h3 className="text-4xl font-black text-emerald-950 tracking-tighter uppercase">Security Check</h3>
                <p className="text-emerald-900/30 text-[10px] font-bold uppercase tracking-[0.2em] leading-relaxed">
