import React, { createContext, useContext, useState, useEffect } from 'react';
import { db, LocalUser } from '../services/db';

interface UserProxy {
  uid: string;
  email: string;
  displayName: string;
}

interface AuthContextType {
  currentUser: UserProxy | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  register: (email: string, password: string, name: string) => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<UserProxy | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if a session exists in localStorage
    const savedUser = localStorage.getItem('botanical_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const login = async (email: string, password: string) => {
    const user = await db.users.where('email').equalsIgnoreCase(email).first();
    if (!user || user.password !== password) {
      throw new Error('auth/user-not-found');
    }

    const userProxy = { uid: user.email, email: user.email, displayName: user.name };
    setCurrentUser(userProxy);
    localStorage.setItem('botanical_user', JSON.stringify(userProxy));
  };

  const register = async (email: string, password: string, name: string) => {
    const exists = await db.users.where('email').equalsIgnoreCase(email).first();
    if (exists) {
      throw new Error('auth/email-already-in-use');
    }

    await db.users.add({
      name,
      email,
      password,
      createdAt: new Date()
    });

    const userProxy = { uid: email, email, displayName: name };
    setCurrentUser(userProxy);
    localStorage.setItem('botanical_user', JSON.stringify(userProxy));
  };

  const signOut = async () => {
    setCurrentUser(null);
    localStorage.removeItem('botanical_user');
  };

  return (
    <AuthContext.Provider value={{ currentUser, loading, login, register, signOut }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

