import Dexie, { type Table } from 'dexie';
import { Message } from '../types';

export interface LocalUser {
  id?: number;
  name: string;
  email: string;
  password: string; // Stored locally for demo simplicity
  createdAt: Date;
}

export interface LocalSession {
  id: string;
  userId: string;
  title: string;
  createdAt: Date;
}

export interface LocalMessage {
  id: string;
  sessionId: string;
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string; // This will store the Base64 string
  timestamp: Date;
}

export class BotanicalDB extends Dexie {
  // Explicitly define primary key types to assist TypeScript with inheritance and Table resolution
  users!: Table<LocalUser, number>;
  sessions!: Table<LocalSession, string>;
  messages!: Table<LocalMessage, string>;

  constructor() {
    super('BotanicalIntelligenceDB');
    // Fix: Using default import 'Dexie' ensures 'this.version' is correctly recognized as a method on the inherited class
    this.version(1).stores({
      users: '++id, &email',
      sessions: 'id, userId, createdAt',
      messages: 'id, sessionId, timestamp'
    });
  }
}

export const db = new BotanicalDB();

