// Fix: Use strictly the recommended import for GoogleGenAI
import { GoogleGenAI } from "@google/genai";

export interface MediaPart {
  inlineData: {
    mimeType: string;
    data: string;
  };
}

export const generateAIResponse = async (
  prompt: string, 
  history: { role: string; parts: ( { text: string } | MediaPart )[] }[],
  image?: { mimeType: string; data: string }
): Promise<string> => {
  // Fix: Initialize GoogleGenAI inside the function as recommended
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const contents: any[] = [...history];
    const currentParts: any[] = [{ text: prompt }];

    if (image) {
      currentParts.push({
        inlineData: {
          mimeType: image.mimeType,
          data: image.data,
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    // Fix: Using 'gemini-3-pro-preview' for complex reasoning/STEM tasks as per guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: `Your name is "FloraExpert". You are a friendly and professional plant health assistant for farmers and botanical enthusiasts.

        RULES FOR RESPONSE:
        1. LANGUAGE: Use simple, professional English. Do not use Hindi or slang.
        2. STRUCTURE: Use clear bullet points and emojis.
           - ## 🌱 Plant Identification
           - ## 🏥 Diagnosis (What's wrong?)
           - ## 🛠️ Care Plan (Step-by-step actions)
           - ## 💧 Vital Stats (Light, Water, Soil - use simple table)
        3. TONE: Helpful, encouraging, and clear.
        4. IMAGES: If an image is provided, analyze the leaves, stem, and soil carefully.
        5. AUTOMATION: Mention that the user can set up automated email alerts for regular health updates on this specific plant.

        Goal: Ensure even a regular gardener can easily understand and take action to save their plant.`,
        temperature: 0.6,
        topP: 0.9,
      }
    });

    // Fix: Use response.text property directly
    return response.text || "I'm sorry, I couldn't process that report. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: System is currently busy. Please try again in a few moments.";
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { db, LocalUser } from '../services/db';

interface UserProxy {
  uid: string;
  email: string;
  displayName: string;
}

interface AuthContextType {
  currentUser: UserProxy | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  register: (email: string, password: string, name: string) => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<UserProxy | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const initializeAuth = async () => {
      try {
        const savedUser = localStorage.getItem('botanical_user');
        if (savedUser) {
          const parsed = JSON.parse(savedUser);
          // Verify user still exists in local DB
          const exists = await db.users.where('email').equalsIgnoreCase(parsed.email).first();
          if (exists) {
            setCurrentUser(parsed);
          } else {
            localStorage.removeItem('botanical_user');
          }
        }
      } catch (err) {
        console.error("Auth initialization failed:", err);
      } finally {
        setLoading(false);
      }
    };
    initializeAuth();
  }, []);

  const login = async (email: string, password: string) => {
    // Standardize email to lowercase for indexing
    const normalizedEmail = email.toLowerCase().trim();
    const user = await db.users.where('email').equalsIgnoreCase(normalizedEmail).first();

    if (!user) {
      throw { code: 'auth/user-not-found' };
    }

    if (user.password !== password) {
      throw { code: 'auth/wrong-password' };
    }

    const userProxy = { uid: normalizedEmail, email: normalizedEmail, displayName: user.name };
    setCurrentUser(userProxy);
    localStorage.setItem('botanical_user', JSON.stringify(userProxy));
  };

  const register = async (email: string, password: string, name: string) => {
    const normalizedEmail = email.toLowerCase().trim();
    const exists = await db.users.where('email').equalsIgnoreCase(normalizedEmail).first();

    if (exists) {
      throw { code: 'auth/email-already-in-use' };
    }

    await db.users.add({
      name: name.trim(),
      email: normalizedEmail,
      password: password,
      createdAt: new Date()
    });

    const userProxy = { uid: normalizedEmail, email: normalizedEmail, displayName: name.trim() };
    setCurrentUser(userProxy);
    localStorage.setItem('botanical_user', JSON.stringify(userProxy));
  };

  const signOut = async () => {
    setCurrentUser(null);
    localStorage.removeItem('botanical_user');
  };

  return (
    <AuthContext.Provider value={{ currentUser, loading, login, register, signOut }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

