            <div className="flex items-center">
              <button 
                type="button"
                onClick={() => setShowCamera(true)}
                className="p-4 text-emerald-600 hover:bg-emerald-50 rounded-full transition-all active:scale-90"
                title="Camera Input"
              >
                <Camera size={22} />
              </button>

              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="p-4 text-emerald-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full transition-all"
                title="Library Upload"
              >
                <ImageIcon size={22} />
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
              </button>
            </div>

            <div className="w-[1px] h-10 bg-emerald-50 mx-2" />

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Query diagnostic engine..."
              rows={1}
