  };

  const startVerification = () => {
    if (!email || !selectedSeason) return;
    setLoading(true);
    setLogs([]);
    addLog(`Initiating SMTP handshake for ${email}...`);
    addLog(`Connecting to smtp.gmail.com:587...`);

    setTimeout(() => {
      addLog(`CRITICAL ERROR: Browser Security Sandbox detected.`);
      addLog(`Direct SMTP (TCP) Sockets are blocked by Chrome/Safari policy.`);
      addLog(`Architectural Note: You must use a Relay (EmailJS/SendGrid) for frontend email.`);
      addLog(`Generating secure verification code for local testing bypass...`);

      const code = Math.floor(100000 + Math.random() * 900000).toString();
      setGeneratedCode(code);

      setTimeout(() => {
        setLoading(false);
        setStep(2);
        setTimer(120);
        addLog(`Code ${code} generated. Simulation mode active.`);
      }, 1000);
    }, 2000);
  };

  const confirmAlert = () => {
    const entered = otp.join('');
    if (entered !== generatedCode) {
      addLog(`Security mismatch. Verification rejected.`);
      return;
    }
    setLoading(true);
    addLog(`Identity confirmed. Storing credentials in local encrypted node...`);
    setTimeout(() => {
      setLoading(false);
      setStep(3);
      addLog(`Seasonal alert bridge established.`);
    }, 2000);
  };

  useEffect(() => {
    if (timer > 0) {
      const interval = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [timer]);

  const currentSeasonData = SEASONS.find(s => s.id === selectedSeason);

  return (
