                      <label className="text-[10px] font-black text-emerald-950/30 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
                        <Globe size={12} /> SMTP Provider
                      </label>
                      <select className="w-full px-6 py-4 bg-emerald-50/50 border border-emerald-100 rounded-2xl font-bold text-emerald-950 outline-none">
