                    <div className="flex items-center gap-2 px-4 py-1.5 bg-emerald-50 text-emerald-600 rounded-full font-black text-[9px] uppercase tracking-widest mt-2">
                      <ShieldCheck size={12} /> Secure Connection Mode
                    </div>
                  </div>

                  <div className="bg-[#021811] rounded-[2.5rem] p-8 text-white relative overflow-hidden border border-white/5">
                    <div className="flex items-center justify-between mb-8 pb-4 border-b border-white/10">
                       <div className="flex items-center gap-4">
                          <Mail size={20} className="text-emerald-400" />
                          <p className="text-sm font-black tracking-tight">{currentSeasonData?.name} Strategy Dispatch</p>
                       </div>
                    </div>
                    <div className="space-y-4">
                      <p className="text-white/40 text-[10px] font-bold uppercase tracking-widest">Growth Recommendations:</p>
                      <div className="grid grid-cols-2 gap-3">
                        {currentSeasonData?.plants.map(plant => (
                          <div key={plant} className="p-3 bg-white/5 rounded-xl border border-white/5 text-[11px] font-black uppercase tracking-wider text-emerald-300">
                            {plant}
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>

                  <button 
                    onClick={() => window.location.reload()}
                    className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-3xl hover:bg-black transition-all uppercase tracking-widest"
                  >
                    Apply All Settings
                  </button>
                </div>
              )}

            </div>
          </div>

          {/* Sidebar / Console */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-[#021811] rounded-[2.5rem] p-6 shadow-2xl h-full flex flex-col min-h-[600px] border border-emerald-900/50">
              <div className="flex items-center gap-3 mb-6 pb-4 border-b border-emerald-900/30">
                <Terminal size={18} className="text-emerald-500" />
