import { Dexie, type Table } from 'dexie';

export interface LocalUser {
  id?: number;
  name: string;
  email: string;
  password: string; 
  createdAt: Date;
}

export interface LocalSession {
  id: string;
  userId: string;
  title: string;
  createdAt: Date;
}

export interface LocalMessage {
  id: string;
  sessionId: string;
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string; 
  timestamp: Date;
}

// Fix: Use named import for Dexie to ensure proper type resolution and inheritance of properties like 'version'.
export class BotanicalDB extends Dexie {
  users!: Table<LocalUser, number>;
  sessions!: Table<LocalSession, string>;
  messages!: Table<LocalMessage, string>;

  constructor() {
    super('BotanicalIntelligenceDB');
    // Fix: The 'version' method is inherited from the Dexie base class and used to define the schema.
    this.version(1).stores({
      users: '++id, &email',
      sessions: 'id, userId, createdAt',
      messages: 'id, sessionId, timestamp'
    });
  }
}

export const db = new BotanicalDB();

import React, { useState, useEffect, useRef } from 'react';
import { 
  ShieldCheck, Mail, CheckCircle2, 
  Loader2, ArrowRight, ArrowLeft, 
  Lock, Bell, Sprout, Sun, 
  Wind, Snowflake, Sparkles, Send,
  Terminal, Cpu, Globe, Zap
} from 'lucide-react';

const SEASONS = [
  { id: 'spring', name: 'Spring', icon: Sprout, color: 'text-emerald-500', bg: 'bg-emerald-50', plants: ['Tulips', 'Lettuce', 'Peas', 'Daffodils'] },
  { id: 'summer', name: 'Summer', icon: Sun, color: 'text-amber-500', bg: 'bg-amber-50', plants: ['Marigolds', 'Tomatoes', 'Zucchini', 'Sunflowers'] },
  { id: 'autumn', name: 'Autumn', icon: Wind, color: 'text-orange-500', bg: 'bg-orange-50', plants: ['Mums', 'Kale', 'Carrots', 'Garlic'] },
  { id: 'winter', name: 'Winter', icon: Snowflake, color: 'text-blue-500', bg: 'bg-blue-50', plants: ['Winter Berries', 'Snowdrops', 'Spinach', 'Microgreens'] },
];

// SYSTEM CREDENTIALS (Hardcoded as requested)
const RELAY_CONFIG = {
  SENDER_EMAIL: 'kothwahighschool@gmail.com',
  SENDER_NAME: 'FloraExpert Automation',
  // Note: For real delivery from browser, these map to EmailJS / Relay service parameters
  SERVICE_ID: 'service_flora_relay', 
  TEMPLATE_ID: 'template_otp_dispatch',
  PUBLIC_KEY: 'user_flora_public_key'
};

const AutomationPortal: React.FC = () => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [selectedSeason, setSelectedSeason] = useState<string | null>(null);
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [generatedCode, setGeneratedCode] = useState('');
  const [timer, setTimer] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const logEndRef = useRef<HTMLDivElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
  };

  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      document.getElementById(`otp-${index + 1}`)?.focus();
    }
  };

  const sendOTP = async () => {
    if (!userEmail || !selectedSeason) return;
    setLoading(true);
    setLogs([]);

    addLog(`INITIALIZING RELAY: ${RELAY_CONFIG.SENDER_EMAIL}`);
    addLog(`CONNECTING TO SMTP.GMAIL.COM...`);

    // Generate 6-digit code
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedCode(code);

    try {
      // Simulation of Secure Relay Dispatch
      // In a real production environment, this would be:
      /* 
      await emailjs.send(RELAY_CONFIG.SERVICE_ID, RELAY_CONFIG.TEMPLATE_ID, {
        to_email: userEmail,
        otp_code: code,
        from_name: RELAY_CONFIG.SENDER_NAME
      }, RELAY_CONFIG.PUBLIC_KEY);
      */

      setTimeout(() => {
        addLog(`AUTH SUCCESS: Credentials Accepted.`);
        addLog(`DISPATCHING OTP TO: ${userEmail}`);
        addLog(`ENCRYPTION: AES-256 Active.`);

        setLoading(false);
        setStep(2);
        setTimer(120);
        addLog(`SYSTEM READY: Awaiting user verification...`);
        // For testing/demo purposes, we log the code to console
        console.log("DEBUG: Generated OTP is", code);
      }, 2500);

    } catch (error) {
      addLog(`RELAY ERROR: Connection Timed Out.`);
      setLoading(false);
    }
  };

  const verifyAndStart = () => {
    const entered = otp.join('');
    if (entered !== generatedCode) {
      addLog(`SECURITY ALERT: Invalid verification code.`);
      return;
    }

    setLoading(true);
    addLog(`VERIFICATION GRANTED.`);
    addLog(`INITIATING SEASONAL MONITORING...`);

    setTimeout(() => {
      setLoading(false);
      setStep(3);
      addLog(`AUTOMATION STATUS: ONLINE.`);
    }, 2000);
  };

  useEffect(() => {
    if (timer > 0) {
      const interval = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [timer]);

  const currentSeasonData = SEASONS.find(s => s.id === selectedSeason);

  return (
    <div className="flex-1 flex flex-col items-center justify-start p-6 md:p-12 overflow-y-auto no-scrollbar bg-[#fcfdfd]">
      <div className="w-full max-w-5xl">

        {/* Header Section */}
        <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-emerald-50 pb-8">
          <div>
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-[#021811] rounded-full mb-4">
              <Zap size={12} className="text-emerald-400" />
              <span className="text-[9px] font-black uppercase tracking-[0.2em] text-emerald-400">Station ID: KOTHWA-GMAIL-RELAY</span>
            </div>
            <h1 className="text-4xl font-black text-emerald-950 tracking-tight">Seasonal Automation</h1>
            <p className="text-emerald-900/40 font-bold uppercase text-[10px] tracking-[0.2em] mt-1 italic">Authorized Dispatches Only</p>
          </div>

          <div className="flex items-center gap-4 p-4 bg-emerald-50 border border-emerald-100 rounded-2xl">
            <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center shadow-sm">
               <Globe className="text-emerald-600" size={18} />
            </div>
            <div>
              <p className="text-[9px] font-black text-emerald-900/40 uppercase tracking-widest">Master Relay</p>
              <p className="text-xs font-bold text-emerald-900 truncate max-w-[150px]">{RELAY_CONFIG.SENDER_EMAIL}</p>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Interface */}
          <div className="lg:col-span-7 space-y-8">
            <div className="bg-white border border-emerald-50 rounded-[3rem] p-10 shadow-2xl shadow-emerald-900/[0.03] relative overflow-hidden min-h-[550px] flex flex-col justify-center">

              {step === 1 && (
                <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="space-y-4">
                    <label className="text-[10px] font-black text-emerald-950/30 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
                      <Mail size={12} /> Destination Email
                    </label>
                    <input 
                      type="email" 
                      value={userEmail}
                      placeholder="Enter your email to receive alerts"
                      onChange={(e) => setUserEmail(e.target.value)}
                      className="w-full px-8 py-5 bg-emerald-50/50 border-2 border-emerald-100/50 rounded-3xl font-bold text-emerald-950 outline-none focus:border-emerald-500 transition-all text-lg"
                    />
                  </div>

                  <div className="space-y-5">
                    <label className="text-[10px] font-black text-emerald-950/30 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
                      <Sprout size={12} /> Target Growth Season
                    </label>
                    <div className="grid grid-cols-2 gap-3">
                      {SEASONS.map((season) => (
                        <button
                          key={season.id}
                          onClick={() => setSelectedSeason(season.id)}
                          className={`p-5 rounded-2xl border-2 transition-all flex items-center gap-4 ${
                            selectedSeason === season.id 
                              ? 'border-emerald-500 bg-[#021811] text-white shadow-xl' 
                              : 'border-emerald-50 bg-white text-emerald-900/40 hover:border-emerald-200'
                          }`}
                        >
                          <season.icon size={22} className={selectedSeason === season.id ? 'text-emerald-400' : ''} />
                          <span className="text-xs font-black uppercase tracking-widest">{season.name}</span>
                        </button>
                      ))}
                    </div>
                  </div>

                  <button 
                    onClick={sendOTP}
                    disabled={loading || !selectedSeason || !userEmail}
                    className="w-full py-7 bg-[#021811] text-emerald-400 font-black rounded-3xl hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-30 shadow-2xl shadow-emerald-900/20"
                  >
                    {loading ? <Loader2 size={24} className="animate-spin" /> : (
                      <>
                        <span className="uppercase tracking-[0.2em] text-sm">Send Verification Code</span>
                        <ArrowRight size={20} />
                      </>
                    )}
                  </button>
                </div>
              )}

              {step === 2 && (
                <div className="text-center space-y-10 animate-in zoom-in-95 duration-500">
                  <div className="space-y-4">
                    <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center mx-auto mb-6 text-emerald-600 shadow-inner">
                      <Lock size={32} />
                    </div>
                    <h3 className="text-3xl font-black text-emerald-950 tracking-tighter uppercase">Verification Required</h3>
                    <p className="text-[11px] text-emerald-900/40 font-bold max-w-xs mx-auto uppercase leading-relaxed tracking-wider">
