                        type="text"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(i, e.target.value)}
                        className="w-12 h-20 text-center text-4xl font-black bg-emerald-50 border-2 border-emerald-100 rounded-2xl text-emerald-950 focus:border-emerald-500 focus:ring-8 focus:ring-emerald-500/5 outline-none transition-all"
                      />
                    ))}
                  </div>

                  <div className="space-y-8">
                    <div className="flex items-center justify-center gap-4">
                      <div className="h-[1px] w-12 bg-emerald-50" />
                      <p className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.3em]">
                        Valid for {Math.floor(timer / 60)}:{(timer % 60).toString().padStart(2, '0')}
                      </p>
                      <div className="h-[1px] w-12 bg-emerald-50" />
                    </div>

                    <button 
                      onClick={verifyAndStart}
                      disabled={loading || otp.some(d => !d)}
                      className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-3xl hover:bg-black transition-all flex items-center justify-center gap-3 disabled:opacity-20 shadow-xl"
                    >
                      {loading ? <Loader2 size={20} className="animate-spin" /> : 'Confirm Identity'}
                    </button>

                    <button 
                      onClick={() => setStep(1)}
                      className="text-[9px] font-black text-emerald-950/30 hover:text-emerald-600 uppercase tracking-widest transition-colors flex items-center justify-center gap-2 mx-auto"
                    >
                      <ArrowLeft size={12} /> Change Email Address
                    </button>
                  </div>
                </div>
              )}

              {step === 3 && (
