import Dexie, { type Table } from 'dexie';

export interface LocalUser {
  id?: number;
  name: string;
  email: string;
  password: string; 
  createdAt: Date;
}

export interface LocalSession {
  id: string;
  userId: string;
  title: string;
  createdAt: Date;
}

export interface LocalMessage {
  id: string;
  sessionId: string;
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string; 
  timestamp: Date;
}

// Fix: Use default import for Dexie to ensure proper class inheritance and prototype method resolution (like 'version') in TypeScript.
export class BotanicalDB extends Dexie {
  users!: Table<LocalUser, number>;
  sessions!: Table<LocalSession, string>;
  messages!: Table<LocalMessage, string>;

  constructor() {
    super('BotanicalIntelligenceDB');
    // Fix: The 'version' method is inherited from the Dexie base class and is used to define the database schema.
    this.version(1).stores({
      users: '++id, &email',
      sessions: 'id, userId, createdAt',
      messages: 'id, sessionId, timestamp'
    });
  }
}

export const db = new BotanicalDB();

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ChatInput from './components/ChatInput';
import AuthPortal from './components/Auth/AuthPortal';
import AutomationPortal from './components/AutomationPortal';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ChatSession, Message } from './types';
import { generateAIResponse } from './services/geminiService';
import { db } from './services/db';
import { Menu, X, ShieldCheck } from 'lucide-react';

const MainApp: React.FC = () => {
  const { currentUser, signOut } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentView, setCurrentView] = useState<'diagnostic' | 'automation'>('diagnostic');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const loadSessions = useCallback(async (autoSelectFirst = false) => {
    if (!currentUser) return;
    const sessionList = await db.sessions
      .where('userId')
      .equals(currentUser.uid)
      .reverse()
      .sortBy('createdAt');

    const sessionsWithMessages = await Promise.all(sessionList.map(async (s) => {
      const messages = await db.messages.where('sessionId').equals(s.id).sortBy('timestamp');
      return {
        ...s,
        messages: messages.map(m => ({
          ...m,
          timestamp: new Date(m.timestamp)
        }))
      };
    }));

    setSessions(sessionsWithMessages);

    if ((!activeSessionId || autoSelectFirst) && sessionsWithMessages.length > 0) {
      setActiveSessionId(sessionsWithMessages[0].id);
    }
  }, [currentUser, activeSessionId]);

  useEffect(() => {
    if (currentUser) {
      loadSessions(true);
    }
  }, [currentUser, loadSessions]);

  const handleNewChat = useCallback(async () => {
    if (!currentUser) return;
    const newId = crypto.randomUUID();

    await db.sessions.add({
      id: newId,
      userId: currentUser.uid,
      title: "New Checkup",
      createdAt: new Date()
    });

    setActiveSessionId(newId);
    setCurrentView('diagnostic');
    setIsSidebarOpen(false); // Close on mobile
    await loadSessions();
  }, [currentUser, loadSessions]);

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!currentUser) return;

    let targetSessionId = activeSessionId;

    if (!targetSessionId) {
      targetSessionId = crypto.randomUUID();
      await db.sessions.add({
        id: targetSessionId,
        userId: currentUser.uid,
        title: image ? "Image Log" : content.slice(0, 15).toUpperCase(),
        createdAt: new Date()
      });
      setActiveSessionId(targetSessionId);
    }

    const userMsgId = crypto.randomUUID();

    await db.messages.add({
      id: userMsgId,
      sessionId: targetSessionId,
      role: 'user',
      content,
      imageUrl: image?.url,
      timestamp: new Date()
    });

    await loadSessions();
    setIsLoading(true);

    try {
      const messagesToUse = (await db.messages.where('sessionId').equals(targetSessionId).sortBy('timestamp')) || [];
      const apiHistory = messagesToUse
        .filter(m => m.id !== userMsgId)
        .map(m => ({
          role: m.role === 'assistant' ? 'model' : 'user',
          parts: [{ text: m.content }]
        }));

      const aiResponseText = await generateAIResponse(
        content, 
        apiHistory, 
        image ? { mimeType: image.mimeType, data: image.data } : undefined
      );

      const assistantMsgId = crypto.randomUUID();

      await db.messages.add({
        id: assistantMsgId,
        sessionId: targetSessionId,
        role: 'assistant',
        content: aiResponseText,
        timestamp: new Date()
      });

      await loadSessions();
    } catch (err) {
      console.error("AI Generation Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) return <AuthPortal />;

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfd] overflow-hidden relative">
      {/* Sidebar Overlay for Mobile */}
      {isSidebarOpen && (
        <div 
          className="lg:hidden fixed inset-0 bg-black/60 backdrop-blur-sm z-[45]" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Responsive Sidebar */}
      <div className={`
        fixed lg:relative inset-y-0 left-0 z-50 transform 
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'} 
        transition-transform duration-300 ease-in-out w-80 shrink-0
      `}>
        <Sidebar 
          sessions={sessions} 
          activeSessionId={activeSessionId} 
          onNewChat={handleNewChat}
          onSelectSession={(id) => {
            setActiveSessionId(id);
            setIsSidebarOpen(false);
          }}
          currentView={currentView}
          onSetView={(view) => {
            setCurrentView(view);
            setIsSidebarOpen(false);
          }}
          automationEnabled={false}
        />
        {/* Mobile Close Button inside Sidebar */}
        <button 
          onClick={() => setIsSidebarOpen(false)}
          className="lg:hidden absolute top-6 right-[-50px] p-2 bg-[#021811] text-emerald-400 rounded-lg"
        >
          <X size={20} />
        </button>
      </div>

      <main className="flex-1 flex flex-col relative h-full min-w-0">
        <header className="h-20 shrink-0 flex items-center justify-between px-4 md:px-10 bg-white border-b border-emerald-50 z-40">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="lg:hidden p-2 text-emerald-950 hover:bg-emerald-50 rounded-xl transition-colors"
            >
              <Menu size={24} />
            </button>
            <div className="flex flex-col">
              <div className="flex items-center gap-2">
                <span className="text-[9px] md:text-[10px] font-black uppercase text-emerald-600 tracking-[0.2em] md:tracking-[0.3em]">Encrypted Node</span>
                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
              </div>
              <span className="text-lg md:text-xl font-black text-emerald-950 tracking-tighter mt-0.5 uppercase truncate max-w-[150px] md:max-w-none">
                {currentView === 'automation' ? 'Automation Suite' : (activeSession?.title || 'Initialization')}
              </span>
            </div>
          </div>
          <button onClick={() => signOut()} className="px-3 md:px-4 py-2 bg-emerald-50 text-emerald-600 text-[9px] md:text-[10px] font-bold rounded-lg uppercase tracking-widest border border-emerald-100 hover:bg-emerald-100 transition-colors">
             <span className="hidden md:inline">Terminate Session</span>
             <span className="md:hidden">Logout</span>
          </button>
        </header>

        <div className="flex-1 relative overflow-hidden flex flex-col">
          {currentView === 'diagnostic' ? (
            <>
              <ChatWindow messages={activeSession?.messages || []} isLoading={isLoading} />
              <ChatInput onSend={handleSendMessage} disabled={isLoading} />
            </>
          ) : (
            <AutomationPortal />
          )}
        </div>
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <MainApp />
    </AuthProvider>
  );
};

