import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ChatInput from './components/ChatInput';
import AuthPortal from './components/Auth/AuthPortal';
import AutomationPortal from './components/AutomationPortal';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ChatSession, Message } from './types';
import { generateAIResponse } from './services/geminiService';
import { db } from './services/db';
import { Menu, X, ShieldCheck, Zap } from 'lucide-react';

const MainApp: React.FC = () => {
  const { currentUser, signOut } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentView, setCurrentView] = useState<'diagnostic' | 'automation'>('diagnostic');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const loadSessions = useCallback(async (autoSelectFirst = false) => {
    if (!currentUser) return;
    const sessionList = await db.sessions
      .where('userId')
      .equals(currentUser.uid)
      .reverse()
      .sortBy('createdAt');

    const sessionsWithMessages = await Promise.all(sessionList.map(async (s) => {
      const messages = await db.messages.where('sessionId').equals(s.id).sortBy('timestamp');
      return {
        ...s,
        messages: messages.map(m => ({
          ...m,
          timestamp: new Date(m.timestamp)
        }))
      };
    }));

    setSessions(sessionsWithMessages);

    if ((!activeSessionId || autoSelectFirst) && sessionsWithMessages.length > 0) {
      setActiveSessionId(sessionsWithMessages[0].id);
    }
  }, [currentUser, activeSessionId]);

  useEffect(() => {
    if (currentUser) {
      loadSessions(true);
    }
  }, [currentUser, loadSessions]);

  const handleNewChat = useCallback(async () => {
    if (!currentUser) return;
    const newId = crypto.randomUUID();

    await db.sessions.add({
      id: newId,
      userId: currentUser.uid,
      title: "New Checkup",
      createdAt: new Date()
    });

    setActiveSessionId(newId);
    setCurrentView('diagnostic');
    setIsSidebarOpen(false); // Close sidebar on mobile after starting new chat
    await loadSessions();
  }, [currentUser, loadSessions]);

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!currentUser) return;

    let targetSessionId = activeSessionId;

    if (!targetSessionId) {
      targetSessionId = crypto.randomUUID();
      await db.sessions.add({
        id: targetSessionId,
        userId: currentUser.uid,
        title: image ? "Image Log" : content.slice(0, 15).toUpperCase(),
        createdAt: new Date()
      });
      setActiveSessionId(targetSessionId);
    }

    const userMsgId = crypto.randomUUID();

    await db.messages.add({
      id: userMsgId,
      sessionId: targetSessionId,
      role: 'user',
      content,
      imageUrl: image?.url,
      timestamp: new Date()
    });

    await loadSessions();
    setIsLoading(true);

    try {
      const messagesToUse = (await db.messages.where('sessionId').equals(targetSessionId).sortBy('timestamp')) || [];
      const apiHistory = messagesToUse
        .filter(m => m.id !== userMsgId)
        .map(m => ({
          role: m.role === 'assistant' ? 'model' : 'user',
          parts: [{ text: m.content }]
        }));

      const aiResponseText = await generateAIResponse(
        content, 
        apiHistory, 
        image ? { mimeType: image.mimeType, data: image.data } : undefined
      );

      const assistantMsgId = crypto.randomUUID();

      await db.messages.add({
        id: assistantMsgId,
        sessionId: targetSessionId,
        role: 'assistant',
        content: aiResponseText,
        timestamp: new Date()
      });

      await loadSessions();
    } catch (err) {
      console.error("AI Generation Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) return <AuthPortal />;

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-[100dvh] w-full bg-[#fcfdfd] overflow-hidden relative">

      {/* Mobile Sidebar Backdrop */}
      {isSidebarOpen && (
        <div 
          className="lg:hidden fixed inset-0 bg-emerald-950/40 backdrop-blur-sm z-[45] animate-in fade-in duration-300" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Responsive Sidebar - Sliding drawer for mobile, fixed for desktop */}
      <div className={`
        fixed lg:relative inset-y-0 left-0 z-50 transform 
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'} 
        transition-transform duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] w-[280px] sm:w-80 shrink-0
      `}>
        <Sidebar 
          sessions={sessions} 
          activeSessionId={activeSessionId} 
          onNewChat={handleNewChat}
          onSelectSession={(id) => {
            setActiveSessionId(id);
            setCurrentView('diagnostic');
            setIsSidebarOpen(false);
          }}
          currentView={currentView}
          onSetView={(view) => {
            setCurrentView(view);
            setIsSidebarOpen(false);
          }}
          automationEnabled={false}
        />

        {/* Mobile Close Button Inside Drawer */}
        <button 
          onClick={() => setIsSidebarOpen(false)}
          className="lg:hidden absolute top-4 -right-12 p-2.5 bg-emerald-950 text-emerald-400 rounded-xl shadow-xl"
        >
          <X size={20} />
        </button>
      </div>

