import React, { useRef, useState, useEffect } from 'react';
import { X, Camera as CameraIcon, RefreshCw, AlertCircle } from 'lucide-react';

interface CameraModalProps {
  onCapture: (dataUrl: string) => void;
  onClose: () => void;
}

const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        // Optimized constraints for mobile back cameras
        const constraints = { 
          video: { 
            facingMode: 'environment',
            width: { ideal: 1280 },
            height: { ideal: 720 }
          }, 
          audio: false 
        };

        const s = await navigator.mediaDevices.getUserMedia(constraints);
        setStream(s);

        if (videoRef.current) {
          videoRef.current.srcObject = s;
          // Crucial for mobile auto-play
          videoRef.current.setAttribute('playsinline', 'true');
          videoRef.current.setAttribute('muted', 'true');
          await videoRef.current.play();
        }
      } catch (err: any) {
        console.error("Camera access error:", err);
        setError("Camera access blocked. Please check browser permissions.");
      }
    }
    startCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }
    };
  }, []);

  const capture = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        // Match capture to video stream resolution
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        onCapture(dataUrl);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#021811] p-0 sm:p-4">
      <div className="relative w-full h-full sm:h-auto sm:max-w-2xl sm:aspect-[3/4] bg-neutral-950 sm:rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col">

        {error ? (
          <div className="flex-1 flex flex-col items-center justify-center p-10 text-center text-white gap-6">
            <AlertCircle size={48} className="text-red-400" />
            <p className="font-bold text-lg">{error}</p>
            <button onClick={onClose} className="px-8 py-3 bg-emerald-500 rounded-full font-black uppercase text-xs">Return</button>
          </div>
        ) : (
          <div className="flex-1 relative bg-black">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted
              className="w-full h-full object-cover" 
            />

            {/* Camera Viewfinder Overlay */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
              <div className="w-64 h-64 border-2 border-white/20 rounded-3xl" />
            </div>
          </div>
        )}

        <canvas ref={canvasRef} className="hidden" />

        <div className="absolute bottom-10 inset-x-0 flex items-center justify-center gap-10 px-6">
          <button 
            onClick={onClose} 
            className="p-5 bg-white/10 backdrop-blur-xl border border-white/10 rounded-full text-white active:scale-90 transition-all"
          >
            <X size={24} />
          </button>

          <button 
            onClick={capture} 
            disabled={!!error}
            className="p-8 bg-emerald-500 rounded-full text-emerald-950 shadow-[0_0_40px_rgba(16,185,129,0.4)] active:scale-95 transition-all disabled:opacity-20"
          >
            <CameraIcon size={36} strokeWidth={2.5} />
          </button>

          <div className="w-14 hidden sm:block" />
        </div>
      </div>
    </div>
  );
};

export default CameraModal;

