const RELAY_CONFIG = {
  SENDER_EMAIL: 'kothwahighschool@gmail.com',
  SENDER_NAME: 'FloraExpert Automation',
  SERVICE_ID: 'service_flora_relay', 
  TEMPLATE_ID: 'template_otp_dispatch',
  PUBLIC_KEY: 'user_flora_public_key'
};

const AutomationPortal: React.FC = () => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [selectedSeason, setSelectedSeason] = useState<string | null>(null);
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [generatedCode, setGeneratedCode] = useState('');
  const [timer, setTimer] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const logEndRef = useRef<HTMLDivElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
  };

  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      document.getElementById(`otp-${index + 1}`)?.focus();
    }
  };

  const sendOTP = async () => {
    if (!userEmail || !selectedSeason) return;
    setLoading(true);
    setLogs([]);

    addLog(`INITIALIZING RELAY...`);
    addLog(`CONNECTING TO GMAIL SMTP...`);

    const code = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedCode(code);

    try {
      setTimeout(() => {
        addLog(`AUTH SUCCESS: Verified.`);
        addLog(`DISPATCHED TO: ${userEmail}`);

        setLoading(false);
        setStep(2);
        setTimer(120);
        addLog(`AWAITING OTP CONFIRMATION...`);
        console.log("DEBUG: Generated OTP is", code);
      }, 1500);
    } catch (error) {
      addLog(`RELAY ERROR.`);
      setLoading(false);
    }
  };

  const verifyAndStart = () => {
    const entered = otp.join('');
    if (entered !== generatedCode) {
      addLog(`SECURITY: Invalid OTP code.`);
      return;
    }

    setLoading(true);
    addLog(`VERIFIED.`);

    setTimeout(() => {
      setLoading(false);
      setStep(3);
      addLog(`STATUS: LIVE.`);
    }, 1500);
  };

  useEffect(() => {
    if (timer > 0) {
      const interval = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [timer]);

  const currentSeasonData = SEASONS.find(s => s.id === selectedSeason);

  return (
