            </div>
            <h1 className="text-2xl md:text-4xl font-black text-emerald-950 tracking-tight leading-tight">Automation Suite</h1>
            <p className="text-emerald-900/40 font-bold uppercase text-[9px] md:text-[10px] tracking-[0.2em] mt-1">Authorized Dispatches Only</p>
          </div>

