import React, { useState, useRef } from 'react';
import { Send, Camera, Image as ImageIcon, X, Loader2, Sparkles, Command } from 'lucide-react';
import CameraModal from './CameraModal';

interface ChatInputProps {
  onSend: (message: string, image?: { mimeType: string, data: string, url: string }) => void;
  disabled?: boolean;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<{ mimeType: string, data: string, url: string } | null>(null);
  const [showCamera, setShowCamera] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage({
          mimeType: file.type,
          data: (reader.result as string).split(',')[1],
          url: reader.result as string
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCameraCapture = (dataUrl: string) => {
    setSelectedImage({
      mimeType: 'image/jpeg',
      data: dataUrl.split(',')[1],
      url: dataUrl
    });
  };

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if ((input.trim() || selectedImage) && !disabled) {
      onSend(input.trim() || "Analyze specimen data.", selectedImage || undefined);
      setInput('');
      setSelectedImage(null);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="absolute bottom-0 left-0 right-0 p-3 md:p-8 pt-10 bg-gradient-to-t from-[#fcfdfd] via-[#fcfdfd] to-transparent pointer-events-none z-30">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      <div className="max-w-4xl mx-auto pointer-events-auto">
        {selectedImage && (
          <div className="mb-3 md:mb-6 flex items-center p-3 md:p-4 bg-white/80 backdrop-blur-2xl rounded-2xl md:rounded-3xl border border-emerald-100 w-fit shadow-xl animate-in slide-in-from-bottom-4">
            <div className="relative w-16 h-16 md:w-24 md:h-24 rounded-xl md:rounded-2xl overflow-hidden border-2 md:border-4 border-white shadow-md">
              <img src={selectedImage.url} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute top-1 right-1 p-1 bg-emerald-950 text-white rounded-full hover:bg-black"
              >
                <X size={10} strokeWidth={3} />
              </button>
            </div>
            <div className="ml-3 md:ml-5 pr-4 md:pr-10">
              <p className="text-[10px] md:text-xs font-black text-emerald-950 uppercase tracking-widest flex items-center gap-2 text-nowrap">
                <Sparkles size={14} className="text-emerald-500 md:w-[16px]" />
                Specimen Active
              </p>
              <p className="text-[8px] md:text-[9px] text-emerald-600/50 uppercase tracking-[0.2em] font-black mt-0.5">Ready for analysis</p>
            </div>
          </div>
        )}

        <div className="relative">
          <div className="flex items-center gap-1 bg-white border border-emerald-50 shadow-xl rounded-[2rem] md:rounded-[3rem] p-1.5 md:p-2 pr-2 md:pr-4 pl-2 md:pl-4 focus-within:border-emerald-500 transition-all duration-500 group">
            <div className="flex items-center gap-0 md:gap-1">
              <button 
                type="button"
                onClick={() => setShowCamera(true)}
                className="p-3 md:p-4 text-emerald-600 hover:bg-emerald-50 rounded-full active:scale-90 transition-colors"
                title="Camera"
              >
                <Camera size={20} className="md:w-[22px]" />
              </button>

              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="p-3 md:p-4 text-emerald-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full active:scale-90 transition-colors"
                title="Library"
              >
                <ImageIcon size={20} className="md:w-[22px]" />
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
              </button>
            </div>

            <div className="w-[1px] h-8 md:h-10 bg-emerald-50 mx-1 md:mx-2" />

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Query node..."
              rows={1}
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm md:text-[15px] font-bold py-3 md:py-4 placeholder-emerald-950/20 text-emerald-950 resize-none no-scrollbar"
              disabled={disabled}
            />

            <button
              type="button"
              onClick={() => handleSubmit()}
              disabled={( !input.trim() && !selectedImage ) || disabled}
              className={`flex items-center justify-center w-10 h-10 md:w-14 md:h-14 rounded-full transition-all duration-500 shrink-0 ${
                (input.trim() || selectedImage) && !disabled
                  ? 'bg-emerald-950 text-emerald-400 shadow-lg hover:scale-105 active:scale-95'
                  : 'bg-emerald-50 text-emerald-100 cursor-not-allowed'
              }`}
            >
              {disabled ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} className="md:w-[24px]" strokeWidth={2.5} />}
            </button>
          </div>

          <div className="hidden md:flex justify-center gap-8 mt-5 opacity-40">
             {[
               { label: 'Analyze Pathogen', icon: Command },
               { label: 'Identify Species', icon: Command }
             ].map(tag => (
               <button 
                 key={tag.label}
                 type="button"
                 onClick={() => setInput(prev => (prev ? prev + ', ' : '') + tag.label)}
                 className="flex items-center gap-2 text-[9px] font-black text-emerald-900 hover:text-emerald-500 uppercase tracking-[0.2em] transition-all"
               >
                 <tag.icon size={12} />
                 {tag.label}
               </button>
             ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatInput;

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../../context/AuthContext';
import { 
  Leaf, Mail, Lock, User, ArrowRight, 
  Loader2, AlertTriangle, Database, 
  ShieldCheck, Terminal, Smartphone,
  Zap, CheckCircle2, RefreshCcw
} from 'lucide-react';

const AuthPortal: React.FC = () => {
  const { login, register } = useAuth();
  const [loading, setLoading] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [regStep, setRegStep] = useState<'details' | 'otp'>('details');

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState<{message: string} | null>(null);

  // OTP State
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [generatedOtp, setGeneratedOtp] = useState('');
  const [timer, setTimer] = useState(0);
  const [dispatchLogs, setDispatchLogs] = useState<string[]>([]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      document.getElementById(`otp-input-${index + 1}`)?.focus();
    }
  };

  const initiateRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!name.trim() || !email || !password) {
      setError({ message: "All research parameters required." });
      return;
    }

    setLoading(true);
    setDispatchLogs(['INITIATING SMTP RELAY...', 'CONNECTING TO smtp.gmail.com:587...']);

    // Simulate SMTP Dispatch with user's credentials logic
    setTimeout(() => {
      const code = Math.floor(100000 + Math.random() * 900000).toString();
      setGeneratedOtp(code);
      setDispatchLogs(prev => [...prev, 'AUTH SUCCESS: kothwahighschool@gmail.com', `DISPATCHING TO: ${email}`, 'MAIL_STATUS: 250 OK']);

      console.log(`[DEV DEBUG] OTP Code for ${email}: ${code}`);

      setLoading(false);
      setRegStep('otp');
      setTimer(120);
    }, 2000);
  };

  const verifyAndFinalize = async () => {
    const entered = otp.join('');
    if (entered !== generatedOtp) {
      setError({ message: "Verification failed: Protocol mismatch." });
      return;
    }

    setLoading(true);
    try {
      await register(email, password, name);
    } catch (err: any) {
      setError({ message: err.message || "Finalization failed." });
      setLoading(false);
    }
  };

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
      await login(email, password);
    } catch (err: any) {
      let msg = "Authentication Rejected";
      if (err.code === 'auth/wrong-password') msg = "Invalid key. Access denied.";
      else if (err.code === 'auth/user-not-found') msg = "Identity not found on this node.";
      setError({ message: msg });
      setLoading(false);
    }
  };

  useEffect(() => {
    if (timer > 0) {
      const interval = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [timer]);

  return (
    <div className="flex h-screen w-full bg-[#f8fbf9] overflow-hidden">
      {/* Immersive Visual Side */}
      <div className="hidden lg:flex w-[50%] bg-[#021811] relative overflow-hidden items-center justify-center p-24">
        <div className="absolute inset-0 z-0">
           <img 
             src="https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?q=80&w=2000&auto=format&fit=crop" 
             className="w-full h-full object-cover opacity-20"
             alt="Botanical Texture"
           />
           <div className="absolute inset-0 bg-gradient-to-tr from-[#021811] via-transparent to-[#021811]/40"></div>
        </div>

        <div className="relative z-10 text-white space-y-12">
           <div className="flex items-center gap-5">
              <div className="w-20 h-20 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center shadow-[0_0_60px_rgba(16,185,129,0.4)]">
                 <Leaf size={42} className="text-[#021811]" />
              </div>
              <div>
                <h1 className="text-7xl font-black tracking-tighter text-white block leading-none">FLORA</h1>
                <span className="text-emerald-500 font-black text-xl tracking-[0.4em] uppercase">Expert v4</span>
              </div>
           </div>

           <div className="space-y-6 max-w-lg">
              <h2 className="text-4xl font-bold text-emerald-50 leading-tight tracking-tight">Secured Botanical Research Node.</h2>
              <div className="flex items-center gap-3 p-4 bg-white/5 rounded-2xl border border-white/10 w-fit">
                <ShieldCheck size={16} className="text-emerald-400" />
                <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">SMTP Relay Enabled</span>
              </div>
              <p className="text-emerald-100/40 text-xl font-medium leading-relaxed">
                Join our private local network for high-accuracy biological diagnostics and health automation.
              </p>
           </div>
        </div>
      </div>

      {/* Auth Form Side */}
      <div className="w-full lg:w-[50%] flex items-center justify-center p-6 md:p-12 relative overflow-y-auto no-scrollbar">
        <div className="w-full max-w-md space-y-10">

          <div className="text-center lg:text-left space-y-3">
            <h3 className="text-4xl font-black text-emerald-950 tracking-tighter uppercase">
              {regStep === 'otp' ? 'Protocol Verification' : (isRegistering ? 'Initialize Identity' : 'Secure Entry')}
            </h3>
            <p className="text-emerald-900/30 text-[10px] font-black uppercase tracking-[0.3em]">
              {regStep === 'otp' ? 'Dispatching code to target endpoint' : (isRegistering ? 'Create your local botanical profile' : 'Verify credentials for node access')}
            </p>
          </div>

          {regStep === 'details' ? (
            <form onSubmit={isRegistering ? initiateRegistration : handleLoginSubmit} className="space-y-6">
              {isRegistering && (
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Researcher Name</label>
                  <div className="relative group">
                    <User className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={18} />
                    <input
                      type="text"
                      required
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      className="w-full pl-14 pr-6 py-4 bg-white border border-emerald-50 rounded-2xl focus:border-emerald-500/50 focus:ring-4 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                      placeholder="e.g. Dr. Green"
                    />
                  </div>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[9px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Work Email</label>
                <div className="relative group">
                  <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={18} />
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-14 pr-6 py-4 bg-white border border-emerald-50 rounded-2xl focus:border-emerald-500/50 focus:ring-4 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                    placeholder="name@research.org"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Access Key</label>
                <div className="relative group">
                  <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={18} />
                  <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-14 pr-6 py-4 bg-white border border-emerald-50 rounded-2xl focus:border-emerald-500/50 focus:ring-4 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                    placeholder="••••••••••••"
                  />
                </div>
              </div>

              {error && (
                <div className="p-4 bg-red-50 border border-red-100 rounded-2xl text-[10px] font-black flex items-start gap-3 text-red-600 animate-in slide-in-from-top-1">
                  <AlertTriangle size={14} className="shrink-0 mt-0.5" />
                  <span className="leading-normal">{error.message.toUpperCase()}</span>
                </div>
              )}

              {loading && isRegistering && (
                <div className="p-4 bg-[#011a12] border border-emerald-900/30 rounded-2xl font-mono text-[9px] text-emerald-400 space-y-1">
                  {dispatchLogs.map((log, i) => (
                    <div key={i} className="flex gap-2">
                      <span className="opacity-30">#</span>
                      <span>{log}</span>
                    </div>
                  ))}
                </div>
              )}

              <button
                type="submit"
                disabled={loading}
                className="w-full py-5 bg-[#021811] text-emerald-400 font-black rounded-2xl hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50 shadow-2xl shadow-emerald-950/20"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : (
                  <>
                    <span className="uppercase tracking-[0.2em]">{isRegistering ? 'Start Handshake' : 'Authorize Entrance'}</span>
                    <ArrowRight size={20} />
                  </>
                )}
              </button>
            </form>
          ) : (
            <div className="space-y-10 animate-in zoom-in-95 duration-300">
               <div className="flex flex-col items-center gap-6">
                  <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center text-emerald-600 shadow-inner">
                    <Smartphone size={32} />
                  </div>
                  <div className="text-center">
                    <p className="text-xs font-bold text-emerald-900/60 uppercase tracking-widest leading-relaxed">
                      Protocol code dispatched to <br/> <span className="text-emerald-950 font-black">{email}</span>
                    </p>
                  </div>
               </div>

               <div className="flex justify-center gap-3">
                  {otp.map((digit, i) => (
                    <input
                      key={i}
                      id={`otp-input-${i}`}
                      type="text"
                      maxLength={1}
                      value={digit}
                      onChange={(e) => handleOtpChange(i, e.target.value)}
                      className="w-12 h-16 md:w-14 md:h-20 text-center text-2xl font-black bg-white border-2 border-emerald-50 rounded-2xl text-emerald-950 focus:border-emerald-500 outline-none transition-all shadow-sm"
                    />
                  ))}
               </div>

               <div className="space-y-4">
                  <button
                    onClick={verifyAndFinalize}
                    disabled={loading || otp.some(d => !d)}
                    className="w-full py-5 bg-emerald-950 text-emerald-400 font-black rounded-2xl hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-30"
                  >
                    {loading ? <Loader2 className="animate-spin" size={20} /> : (
                      <>
                        <Zap size={18} />
                        <span className="uppercase tracking-[0.2em]">Finalize Verification</span>
                      </>
                    )}
                  </button>

                  <div className="flex items-center justify-between px-2">
                    <p className="text-[10px] font-black text-emerald-900/40 uppercase tracking-widest">
                      Expires: <span className={timer < 30 ? 'text-red-500' : 'text-emerald-600'}>{Math.floor(timer / 60)}:{(timer % 60).toString().padStart(2, '0')}</span>
                    </p>
                    <button 
                      onClick={() => setRegStep('details')}
                      className="text-[10px] font-black text-emerald-600 uppercase tracking-widest hover:underline"
                    >
                      Change Email
                    </button>
                  </div>
               </div>
            </div>
          )}

          <div className="text-center pt-8 border-t border-emerald-50">
            <button
              onClick={() => { 
                setIsRegistering(!isRegistering); 
                setRegStep('details');
                setError(null); 
              }}
              className="text-[10px] font-black text-emerald-950/40 hover:text-emerald-950 transition-colors uppercase tracking-[0.3em]"
            >
              {isRegistering ? 'Already have an identity? Log In' : 'First time here? Register Profile'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
