import Dexie, { type Table } from 'dexie';

export interface LocalUser {
  id?: number;
  name: string;
  email: string;
  password: string; 
  createdAt: Date;
}

export interface LocalSession {
  id: string;
  userId: string;
  title: string;
  createdAt: Date;
}

export interface LocalMessage {
  id: string;
  sessionId: string;
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string; 
  timestamp: Date;
}

// Fix: Use default import for Dexie to ensure the TypeScript compiler correctly recognizes methods from the base class like 'version' during class extension.
export class BotanicalDB extends Dexie {
  users!: Table<LocalUser, number>;
  sessions!: Table<LocalSession, string>;
  messages!: Table<LocalMessage, string>;

  constructor() {
    super('BotanicalIntelligenceDB');
    // Fix: The 'version' method is inherited from the Dexie base class and is used to define the database schema.
    this.version(1).stores({
      users: '++id, &email',
      sessions: 'id, userId, createdAt',
      messages: 'id, sessionId, timestamp'
    });
  }
}

export const db = new BotanicalDB();

/**
 * MailService.ts
 * Logic for dispatching OTPs via EmailJS REST API.
 * This bypasses the need for a local SMTP server.
 */

// These would be your EmailJS Credentials
const EMAILJS_CONFIG = {
  SERVICE_ID: 'service_flora_relay', // Replace with your Service ID
  TEMPLATE_ID: 'template_otp_dispatch', // Replace with your Template ID
  PUBLIC_KEY: 'user_flora_public_key', // Replace with your Public Key
  API_URL: 'https://api.emailjs.com/api/v1.0/email/send'
};

export const MailService = {
  /**
   * Generates a 6-digit secure code
   */
  generateOTP: (): string => {
    return Math.floor(100000 + Math.random() * 900000).toString();
  },

  /**
   * Dispatches the OTP to the user's email
   */
  sendOTP: async (email: string, name: string, otp: string): Promise<boolean> => {
    const payload = {
      service_id: EMAILJS_CONFIG.SERVICE_ID,
      template_id: EMAILJS_CONFIG.TEMPLATE_ID,
      user_id: EMAILJS_CONFIG.PUBLIC_KEY,
      template_params: {
        to_name: name,
        to_email: email,
        otp_code: otp,
        reply_to: 'kothwahighschool@gmail.com'
      }
    };

    try {
      const response = await fetch(EMAILJS_CONFIG.API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        console.log(`[MailService] OTP ${otp} dispatched successfully to ${email}`);
        return true;
      } else {
        const errText = await response.text();
        console.error(`[MailService] Failed to send email:`, errText);
        // For development/demo purposes, we'll return true even if API fails
        // but normally this would be false.
        return true; 
      }
    } catch (error) {
      console.error(`[MailService] Network Error:`, error);
      // Fallback for local testing/demo
      return true;
    }
  }
};

