                 <Leaf size={42} className="text-[#021811]" />
              </div>
              <div>
                <h1 className="text-7xl font-black tracking-tighter block leading-none">FLORA</h1>
                <span className="text-emerald-500 font-black text-xl tracking-[0.4em] uppercase">Intelligence v4</span>
              </div>
           </div>

           <div className="space-y-6 max-w-lg">
              <h2 className="text-4xl font-bold text-emerald-50 leading-tight tracking-tight">Secured Botanical Research Node.</h2>
              <div className="flex items-center gap-3 p-4 bg-white/5 rounded-2xl border border-white/10 w-fit">
                <ShieldCheck size={16} className="text-emerald-400" />
                <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Master Relay Active</span>
              </div>
              <p className="text-emerald-100/40 text-xl font-medium leading-relaxed">
                A local-first intelligence platform for high-precision botanical analysis and seasonal automation.
              </p>
           </div>
        </div>
      </div>

      {/* Auth Form Side */}
      <div className="w-full lg:w-[50%] flex items-center justify-center p-6 md:p-12 relative overflow-y-auto no-scrollbar">
