  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState<{message: string} | null>(null);

  // OTP State
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [generatedOtp, setGeneratedOtp] = useState('');
  const [timer, setTimer] = useState(0);
  const [apiLogs, setApiLogs] = useState<string[]>([]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      document.getElementById(`otp-input-${index + 1}`)?.focus();
    }
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      document.getElementById(`otp-input-${index - 1}`)?.focus();
    }
  };

  const initiateRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!name.trim() || !email || !password) {
      setError({ message: "All parameters required for identification." });
      return;
    }

    setLoading(true);
    setApiLogs(['INITIALIZING SMTP_RELAY...', 'AUTH: Secure Token Handshake...']);

    const newOtp = MailService.generateOTP();
    setGeneratedOtp(newOtp);

    setApiLogs(prev => [...prev, `ENDPOINT: ${email}`, 'RELAY: Handshaking with SMTPJS...']);

    const success = await MailService.sendOTP(email, name, newOtp);

    if (success) {
      setApiLogs(prev => [...prev, 'STATUS: HANDSHAKE_OK - Sequence Dispatched.']);
      setTimeout(() => {
        setLoading(false);
        setRegStep('otp');
        setTimer(120);
      }, 1000);
    } else {
      setError({ message: "SMTP Handshake failed. Terminal isolated." });
      setLoading(false);
    }
  };

  const verifyAndFinalize = async () => {
    const entered = otp.join('');
    if (entered !== generatedOtp) {
      setError({ message: "Verification failed: Sequence mismatch." });
      return;
    }

    setLoading(true);
    try {
      await register(email, password, name);
    } catch (err: any) {
      setError({ message: err.message || "Protocol finalization error." });
      setLoading(false);
    }
  };

