                    </p>
                  </div>
               </div>

               <div className="flex justify-center gap-3">
                  {otp.map((digit, i) => (
                    <input
                      key={i}
                      id={`otp-input-${i}`}
                      type="text"
                      maxLength={1}
                      value={digit}
                      onChange={(e) => handleOtpChange(i, e.target.value)}
                      onKeyDown={(e) => handleKeyDown(i, e)}
                      className="w-12 h-16 md:w-14 md:h-20 text-center text-2xl font-black bg-white border-2 border-emerald-50 rounded-2xl text-emerald-950 focus:border-emerald-500 outline-none transition-all shadow-sm"
                    />
                  ))}
               </div>

               <div className="space-y-4">
                  <button
                    onClick={verifyAndFinalize}
                    disabled={loading || otp.some(d => !d)}
                    className="w-full py-5 bg-emerald-950 text-emerald-400 font-black rounded-2xl hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-30"
                  >
                    {loading ? <Loader2 className="animate-spin" size={20} /> : (
                      <>
                        <Zap size={18} />
                        <span className="uppercase tracking-[0.2em]">Confirm Sequence</span>
                      </>
                    )}
                  </button>

                  <div className="flex items-center justify-between px-2">
                    <p className="text-[10px] font-black text-emerald-900/40 uppercase tracking-widest">
                      Expires: <span className={timer < 30 ? 'text-red-500' : 'text-emerald-600'}>{Math.floor(timer / 60)}:{(timer % 60).toString().padStart(2, '0')}</span>
                    </p>
                    <button 
                      onClick={() => setRegStep('details')}
                      className="flex items-center gap-1 text-[10px] font-black text-emerald-600 uppercase tracking-widest hover:underline"
                    >
                      <ChevronLeft size={14} /> Back
                    </button>
                  </div>
               </div>
            </div>
          )}

          <div className="text-center pt-8 border-t border-emerald-50">
            <button
              onClick={() => { 
                setIsRegistering(!isRegistering); 
                setRegStep('details');
                setError(null); 
              }}
              className="text-[10px] font-black text-emerald-950/40 hover:text-emerald-950 transition-colors uppercase tracking-[0.3em]"
            >
              {isRegistering ? 'Returning researcher? Access Node' : 'New to node? Establish Relay'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPortal;

import React, { useState, useEffect, useRef } from 'react';
import { MailService } from '../services/MailService';
import { 
  ShieldCheck, Mail, CheckCircle2, 
  Loader2, ArrowRight, Lock, 
  Sprout, Sun, Wind, Snowflake, 
  Zap, Terminal, Cpu, Globe
} from 'lucide-react';

const SEASONS = [
  { id: 'spring', name: 'Spring', icon: Sprout, color: 'text-emerald-500', bg: 'bg-emerald-50', plants: ['Tulips', 'Lettuce', 'Peas'] },
  { id: 'summer', name: 'Summer', icon: Sun, color: 'text-amber-500', bg: 'bg-amber-50', plants: ['Marigolds', 'Tomatoes', 'Zucchini'] },
  { id: 'autumn', name: 'Autumn', icon: Wind, color: 'text-orange-500', bg: 'bg-orange-50', plants: ['Mums', 'Kale', 'Carrots'] },
  { id: 'winter', name: 'Winter', icon: Snowflake, color: 'text-blue-500', bg: 'bg-blue-50', plants: ['Berries', 'Snowdrops', 'Spinach'] },
];

const AutomationPortal: React.FC = () => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [selectedSeason, setSelectedSeason] = useState<string | null>(null);
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [generatedCode, setGeneratedCode] = useState('');
  const [timer, setTimer] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const logEndRef = useRef<HTMLDivElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
  };

  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      document.getElementById(`otp-${index + 1}`)?.focus();
    }
  };

  const sendOTP = async () => {
    if (!userEmail || !selectedSeason) return;
    setLoading(true);
    setLogs([]);

    addLog(`INITIATING SMTP_RELAY...`);
    addLog(`STATUS: SECURE_TOKEN_HANDSHAKE READY.`);

    const code = MailService.generateOTP();
    setGeneratedCode(code);

    addLog(`DISPATCHING TO: ${userEmail}...`);

    const success = await MailService.sendOTP(userEmail, 'Flora Researcher', code);

    if (success) {
      addLog(`STATUS: HANDSHAKE_OK.`);
      setLoading(false);
      setStep(2);
      setTimer(120);
      addLog(`AWAITING SEQUENCE VERIFICATION...`);
    } else {
      addLog(`ERROR: SMTP Relay handoff failed.`);
      setLoading(false);
    }
  };

  const verifyAndStart = () => {
    const entered = otp.join('');
    if (entered !== generatedCode) {
      addLog(`SECURITY: Sequence mismatch detected.`);
      return;
    }

    setLoading(true);
    addLog(`VERIFIED. Binding relay to endpoint...`);

    setTimeout(() => {
      setLoading(false);
      setStep(3);
      addLog(`STATUS: SMTP_RELAY ACTIVE & MONITORING.`);
    }, 1500);
  };

  useEffect(() => {
    if (timer > 0) {
      const interval = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [timer]);

  const currentSeasonData = SEASONS.find(s => s.id === selectedSeason);

  return (
    <div className="flex-1 flex flex-col items-center justify-start p-4 md:p-10 lg:p-12 overflow-y-auto no-scrollbar bg-[#fcfdfd]">
      <div className="w-full max-w-5xl">

        <header className="mb-6 md:mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-emerald-50 pb-6 md:pb-8">
          <div>
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-[#021811] rounded-full mb-3">
              <Zap size={10} className="text-emerald-400" />
              <span className="text-[9px] font-black uppercase tracking-[0.2em] text-emerald-400">Master Relay Node</span>
            </div>
            <h1 className="text-2xl md:text-4xl font-black text-emerald-950 tracking-tight leading-tight">Automation Suite</h1>
          </div>

          <div className="flex items-center gap-3 p-3 bg-emerald-50 border border-emerald-100 rounded-2xl">
            <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-sm shrink-0">
               <Globe className="text-emerald-600" size={16} />
            </div>
            <div className="min-w-0">
              <p className="text-[8px] font-black text-emerald-900/40 uppercase tracking-widest">Protocol Type</p>
              <p className="text-[10px] font-bold text-emerald-900 truncate">SMTP Relay Handshake</p>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-7">
            <div className="bg-white border border-emerald-50 rounded-[2rem] md:rounded-[3.5rem] p-6 md:p-12 shadow-xl shadow-emerald-950/5 relative overflow-hidden flex flex-col justify-center min-h-[400px]">

              {step === 1 && (
                <div className="space-y-6 md:space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="space-y-3">
                    <label className="text-[9px] font-black text-emerald-950/30 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
                      <Mail size={12} /> Target Endpoint
                    </label>
                    <input 
                      type="email" 
                      value={userEmail}
                      placeholder="Enter researcher email"
                      onChange={(e) => setUserEmail(e.target.value)}
                      className="w-full px-5 py-4 md:px-8 md:py-5 bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl md:rounded-[2rem] font-bold text-emerald-950 outline-none focus:border-emerald-500 transition-all text-sm md:text-lg"
                    />
                  </div>

                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-emerald-950/30 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
                      <Sprout size={12} /> Seasonal Protocol
                    </label>
                    <div className="grid grid-cols-2 gap-3">
                      {SEASONS.map((season) => (
                        <button
                          key={season.id}
                          onClick={() => setSelectedSeason(season.id)}
                          className={`p-4 md:p-6 rounded-xl md:rounded-[2rem] border-2 transition-all flex flex-col md:flex-row items-center gap-3 ${
                            selectedSeason === season.id 
                              ? 'border-emerald-500 bg-emerald-950 text-white shadow-xl' 
                              : 'border-emerald-50 bg-white text-emerald-900/40 hover:border-emerald-200'
                          }`}
                        >
                          <season.icon size={20} className={selectedSeason === season.id ? 'text-emerald-400' : ''} />
                          <span className="text-[10px] md:text-xs font-black uppercase tracking-widest">{season.name}</span>
                        </button>
                      ))}
                    </div>
                  </div>

                  <button 
                    onClick={sendOTP}
                    disabled={loading || !selectedSeason || !userEmail}
                    className="w-full py-5 md:py-7 bg-emerald-950 text-emerald-400 font-black rounded-2xl md:rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-30 shadow-2xl shadow-emerald-950/20"
                  >
                    {loading ? <Loader2 size={24} className="animate-spin" /> : (
                      <>
                        <span className="uppercase tracking-[0.2em] text-[10px] md:text-sm">Initiate Handshake</span>
                        <ArrowRight size={18} />
                      </>
                    )}
                  </button>
                </div>
              )}

              {step === 2 && (
                <div className="text-center space-y-8 animate-in zoom-in-95 duration-500">
                  <div className="space-y-4">
                    <div className="w-16 h-16 md:w-24 md:h-24 bg-emerald-50 rounded-[1.5rem] md:rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-emerald-600 shadow-inner">
                      <Lock size={28} />
                    </div>
                    <h3 className="text-2xl md:text-3xl font-black text-emerald-950 tracking-tighter uppercase">Code Required</h3>
                    <p className="text-[10px] text-emerald-900/40 font-bold max-w-xs mx-auto uppercase tracking-wider">
                      Handshake sequence sent to <span className="text-emerald-950">{userEmail}</span>.
                    </p>
                  </div>

                  <div className="flex justify-center gap-2 md:gap-3">
                    {otp.map((digit, i) => (
                      <input
                        key={i}
                        id={`otp-${i}`}
                        type="text"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(i, e.target.value)}
                        className="w-10 h-14 md:w-12 md:h-20 text-center text-2xl md:text-4xl font-black bg-emerald-50 border-2 border-emerald-100 rounded-xl md:rounded-2xl text-emerald-950 focus:border-emerald-500 outline-none transition-all shadow-sm"
                      />
                    ))}
                  </div>

                  <div className="space-y-6">
                    <p className="text-[9px] font-black text-emerald-600 uppercase tracking-[0.3em]">
                      Handshake window: {timer}s
                    </p>
                    <button 
                      onClick={verifyAndStart}
                      disabled={loading || otp.some(d => !d)}
                      className="w-full py-5 md:py-6 bg-emerald-950 text-emerald-400 font-black rounded-2xl md:rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-3 disabled:opacity-20 shadow-xl"
                    >
                      {loading ? <Loader2 size={20} className="animate-spin" /> : 'Confirm Sequence'}
                    </button>
                  </div>
                </div>
              )}

              {step === 3 && (
                <div className="space-y-6 md:space-y-10 animate-in fade-in zoom-in-95 duration-1000 text-center">
                  <div className="flex flex-col items-center">
                    <div className="w-20 h-20 md:w-28 md:h-28 bg-emerald-500 rounded-[2rem] md:rounded-[3rem] flex items-center justify-center text-white shadow-2xl mb-6">
                      <CheckCircle2 size={40} />
                    </div>
                    <h3 className="text-2xl md:text-4xl font-black text-emerald-950 tracking-tighter uppercase">Endpoint Bound</h3>
                    <p className="text-[10px] font-bold text-emerald-900/40 uppercase tracking-widest">SMTP Relay Live</p>
                  </div>

                  <div className="bg-emerald-950 rounded-[1.5rem] md:rounded-[2.5rem] p-6 md:p-10 text-white relative overflow-hidden border border-white/5 text-left">
                    <div className="flex items-center gap-4 mb-6">
                      <div className="p-3 bg-white/10 rounded-xl">
                        <Zap size={18} className="text-emerald-400" />
                      </div>
                      <div>
                        <p className="text-[8px] font-bold text-emerald-400/60 uppercase tracking-widest">Secure Link</p>
                        <p className="text-base md:text-lg font-black tracking-tight uppercase">Monitoring Established</p>
                      </div>
                    </div>
                    <p className="text-xs text-emerald-100/40 uppercase font-black tracking-widest">Protocol: {currentSeasonData?.name} Monitoring</p>
                  </div>

                  <button 
                    onClick={() => window.location.reload()}
                    className="w-full py-5 bg-emerald-50 text-emerald-900 font-black rounded-2xl md:rounded-[2rem] hover:bg-emerald-100 transition-all uppercase tracking-[0.2em] text-[10px]"
                  >
                    Terminate Protocol
                  </button>
                </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-5">
            <div className="bg-emerald-950 rounded-[1.5rem] md:rounded-[3rem] p-6 md:p-10 shadow-2xl h-full flex flex-col border border-emerald-900/30 min-h-[250px]">
              <div className="flex items-center justify-between mb-6 pb-4 border-b border-emerald-900/20">
                <div className="flex items-center gap-3">
                  <Terminal size={16} className="text-emerald-500" />
                  <span className="text-[9px] font-black text-emerald-500 uppercase tracking-[0.3em]">Relay Console</span>
                </div>
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
              </div>

              <div className="flex-1 overflow-y-auto no-scrollbar font-mono text-[9px] md:text-[11px] space-y-3">
                {logs.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center opacity-10 space-y-3 grayscale">
                    <Cpu size={32} />
                    <p className="text-[8px] font-black uppercase tracking-[0.2em]">Console Awaiting Port</p>
                  </div>
                ) : (
                  logs.map((log, i) => (
                    <div key={i} className="leading-relaxed animate-in fade-in slide-in-from-left-2 text-emerald-400/70">
                      <span className="text-emerald-900 mr-2 opacity-50">#</span>
                      {log}
                    </div>
                  ))
                )}
                <div ref={logEndRef} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AutomationPortal;
